import{c as s,cG as i,cb as a,c8 as t,cf as d,cT as l,ce as e}from"./chunks/framework.BlkIsu1j.js";const n=JSON.parse('{"title":"17. C 扩展：压缩指令","description":"","frontmatter":{"title":"17. C 扩展：压缩指令","outline":"deep","layout":"doc","prev":{"text":"16. F 与 D 扩展：浮点指令","link":"/lang/assembly/16_f_d_extension"},"next":{"text":"18. 与 C 语言互操作","link":"/lang/assembly/18_c_interop"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/17_c_extension.md","filePath":"lang/assembly/17_c_extension.md","lastUpdated":1780202472000}'),h={id:"frontmatter-title",tabindex:"-1"};const r=s({name:"lang/assembly/17_c_extension.md"},[["render",function(s,n,r,p,k,c){return i(),a("div",null,[t("h1",h,[d(l(s.$frontmatter.title)+" ",1),n[0]||(n[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),n[1]||(n[1]=e('<p>前面 16 章中所有指令都是 32 位定长编码。RISC-V 的基础设计理念之一是&quot;固定长度指令简化取指和解码&quot;，但固定 32 位也意味着代码体积偏大——在指令缓存有限的嵌入式场景中，代码密度直接影响性能和功耗。C 扩展（Compressed Instructions）以 16 位指令编码覆盖最频繁使用的操作，将代码体积压缩 25%-30%。本章剖析压缩指令的设计约束、编码策略、常用指令表、以及对汇编程序员的影响。</p><h2 id="压缩指令概述" tabindex="-1">压缩指令概述 <a class="header-anchor" href="#压缩指令概述" aria-label="Permalink to “压缩指令概述”">​</a></h2><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to “核心思想”">​</a></h3><p>C 扩展的每一条 16 位压缩指令都<strong>唯一映射到一条标准 32 位指令</strong>。<code>c.addi sp, -16</code> 的底层完全等同于 <code>addi sp, sp, -16</code>——不是新的 ISA，是同一条架构指令的短编码。这个设计意味着：</p><ul><li><strong>处理器不需要两套执行单元</strong>：解码器将 16 位指令展开为 32 位内部表示，ALU 只看到一种格式</li><li><strong>无需新的汇编语义</strong>：<code>c.add</code> 和 <code>add</code> 在程序员视角下完全等价</li><li><strong>汇编器自动选择</strong>：写 <code>add t0, t1, t2</code>，若 t0/t1/t2 都在 x8-x15 范围内，汇编器自动生成 <code>c.add t0, t1</code>（2 字节）；否则生成 <code>add t0, t1, t2</code>（4 字节）</li></ul><h3 id="为什么-16-位编码有效" tabindex="-1">为什么 16 位编码有效 <a class="header-anchor" href="#为什么-16-位编码有效" aria-label="Permalink to “为什么 16 位编码有效”">​</a></h3><p>RISC-V 的分析统计显示：典型程序中 50%-60% 的指令可以用压缩形式表达。原因是：</p><ol><li><strong>寄存器使用的 Pareto 分布</strong>：x8-x15（s0-s1, a0-a5）八个寄存器承载了大部分数据流</li><li><strong>立即数集中在窄范围</strong>：大多数立即数是 0、±1、±2、小偏移——不需要 12 位全宽</li><li><strong>指令类型高度集中</strong>：load/store/branch/add 占指令总数的 80%+——仅覆盖这些类别就有极大收益</li></ol><h3 id="适用场景与代价" tabindex="-1">适用场景与代价 <a class="header-anchor" href="#适用场景与代价" aria-label="Permalink to “适用场景与代价”">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>代价</th></tr></thead><tbody><tr><td>代码体积降低 25%-30%</td><td>取指逻辑复杂化（需处理 16 位边界对齐）</td></tr><tr><td>指令缓存命中率提高（同样的缓存可容纳更多指令）</td><td>16 位指令和 32 位指令<strong>可以混合</strong>在一个 cache line 中——需额外的预解码标记位</td></tr><tr><td>取指带宽有效提升（每次取 32 位可拿回 2 条压缩指令）</td><td>压缩指令受限操作数（见下文）</td></tr></tbody></table><p>对于有指令缓存的处理器，C 扩展的收益远大于成本；对于最小面积 MCU，C 扩展可大幅缩小 flash 占用。</p><h2 id="设计约束" tabindex="-1">设计约束 <a class="header-anchor" href="#设计约束" aria-label="Permalink to “设计约束”">​</a></h2><h3 id="寄存器访问限制" tabindex="-1">寄存器访问限制 <a class="header-anchor" href="#寄存器访问限制" aria-label="Permalink to “寄存器访问限制”">​</a></h3><p>C 扩展将压缩指令的操作数限制在 <strong>x8-x15</strong>（s0, s1, a0-a5）八个寄存器上——这个子集承载了典型代码中 70%+ 的寄存器引用。指令编码用 3 位（而非 5 位）表示寄存器编号，节省 4 位：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 完整寄存器集的指令（32 位）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t0, t1, t2          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0/t1/t2 = x5/x6/x7 —— 任何 x0-x31</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 压缩指令受限为 x8-x15（16 位）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> s0, a0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # s0=x8, a0=x10 —— 必须在 x8-x15 范围内</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x15, x12           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # x15=a5, x12=a2 —— 也在 x8-x15 范围内</span></span></code></pre></div><p>汇编器自动判断：当目标代码中的所有操作数都在 x8-x15 内时，生成压缩形式；否则生成 32 位形式。大多数时间你不需要意识到这种切换。</p><h3 id="立即数范围减小" tabindex="-1">立即数范围减小 <a class="header-anchor" href="#立即数范围减小" aria-label="Permalink to “立即数范围减小”">​</a></h3>',17)),n[2]||(n[2]=t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"压缩指令"),t("th",null,"立即数位宽"),t("th",null,"对应 32 位指令的立即数位宽"),t("th",null,"限制")])]),t("tbody",null,[t("tr",null,[t("td",null,[t("code",null,"c.addi")]),t("td",null,"6 位有符号"),t("td",null,"12 位有符号"),t("td",null,"-32..+31")]),t("tr",null,[t("td",null,[t("code",null,"c.addi16sp")]),t("td",null,"10 位有符号（×16）"),t("td",null,"12 位有符号"),t("td",null,"-512..+496, 步长 16")]),t("tr",null,[t("td",null,[t("code",null,"c.lui")]),t("td",null,"6 位非零"),t("td",null,"20 位"),t("td",{"x0,":"",x2:""},"rd !=")]),t("tr",null,[t("td",null,[t("code",null,"c.li")]),t("td",null,"6 位有符号"),t("td",null,"12 位有符号"),t("td",null,"rd != x0")]),t("tr",null,[t("td",null,[t("code",null,"c.slli")]),t("td",null,"6 位无符号（1..63）"),t("td",null,"6 位无符号"),t("td",null,"shift != 0")]),t("tr",null,[t("td",null,[t("code",null,"c.lwsp")]),t("td",null,"6 位无符号（×4）"),t("td",null,"12 位有符号"),t("td",null,"相对 sp")]),t("tr",null,[t("td",null,[t("code",null,"c.sdsp")]),t("td",null,"6 位无符号（×8）"),t("td",null,"12 位有符号"),t("td",null,"相对 sp")])])],-1)),n[3]||(n[3]=e('<p>关键模式：压缩立即数通常更窄，且许多是缩放过的（×4 用于 32 位访问，×8 用于 64 位访问）——这反而匹配最常见的内存布局模式（栈帧中的 32/64 位值）。</p><h3 id="无三操作数字段" tabindex="-1">无三操作数字段 <a class="header-anchor" href="#无三操作数字段" aria-label="Permalink to “无三操作数字段”">​</a></h3><p>C 扩展的寄存器-寄存器运算全部是<strong>二操作数</strong>（目标寄存器也是第一源寄存器，即破坏性操作）：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 32 位格式：非破坏性，独立 rd</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t0, t1, t2          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = t1 + t2; t1 和 t2 不变</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 16 位压缩格式：破坏性，rd = rs1（即 rd 也是 rs1）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t0, t1             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = t0 + t1;  t0 被覆盖</span></span></code></pre></div><p>这是个可察觉的限制——分配寄存器时需要为压缩指令腾出&quot;破坏目标&quot;的操作模式。但汇编器依然透明处理：写 <code>add t0, t0, t1</code> 时生成 <code>c.add t0, t1</code>。</p><h2 id="常用压缩指令表" tabindex="-1">常用压缩指令表 <a class="header-anchor" href="#常用压缩指令表" aria-label="Permalink to “常用压缩指令表”">​</a></h2><h3 id="整数运算类" tabindex="-1">整数运算类 <a class="header-anchor" href="#整数运算类" aria-label="Permalink to “整数运算类”">​</a></h3><table tabindex="0"><thead><tr><th>压缩指令</th><th>等价 32 位</th><th>约束</th></tr></thead><tbody><tr><td><code>c.addi rd, imm</code></td><td><code>addi rd, rd, imm</code></td><td>rd != x0, imm ∈ [-32, 31]</td></tr><tr><td><code>c.addi16sp imm</code></td><td><code>addi sp, sp, imm</code></td><td>imm 10 位 × 16 = [-512, 496]</td></tr><tr><td><code>c.addi4spn rd&#39;, uimm</code></td><td><code>addi rd, sp, uimm</code></td><td>rd ∈ x8-x15, uimm × 4</td></tr><tr><td><code>c.li rd, imm</code></td><td><code>addi rd, x0, imm</code></td><td>rd != x0, imm ∈ [-32, 31]</td></tr><tr><td><code>c.lui rd, imm</code></td><td><code>lui rd, imm</code></td><td>rd != {x0, x2}, imm != 0</td></tr><tr><td><code>c.add rd, rs2</code></td><td><code>add rd, rd, rs2</code></td><td>rd != x0</td></tr><tr><td><code>c.sub rd, rs2</code></td><td><code>sub rd, rd, rs2</code></td><td>—</td></tr><tr><td><code>c.and rd, rs2</code></td><td><code>and rd, rd, rs2</code></td><td>—</td></tr><tr><td><code>c.or rd, rs2</code></td><td><code>or rd, rd, rs2</code></td><td>—</td></tr><tr><td><code>c.xor rd, rs2</code></td><td><code>xor rd, rd, rs2</code></td><td>—</td></tr><tr><td><code>c.mv rd, rs2</code></td><td><code>add rd, rs2, x0</code></td><td>rd != x0, rs2 != x0</td></tr><tr><td><code>c.nop</code></td><td><code>addi x0, x0, 0</code></td><td>—</td></tr><tr><td><code>c.slli rd, shamt</code></td><td><code>slli rd, rd, shamt</code></td><td>rd != x0, shamt ∈ [1, 63]</td></tr><tr><td><code>c.srli rd, shamt</code></td><td><code>srli rd, rd, shamt</code></td><td>—</td></tr><tr><td><code>c.srai rd, shamt</code></td><td><code>srai rd, rd, shamt</code></td><td>—</td></tr></tbody></table><h3 id="load-store-类" tabindex="-1">Load/Store 类 <a class="header-anchor" href="#load-store-类" aria-label="Permalink to “Load/Store 类”">​</a></h3><table tabindex="0"><thead><tr><th>压缩指令</th><th>等价 32 位</th><th>约束</th></tr></thead><tbody><tr><td><code>c.lw rd&#39;, offset(rs1&#39;)</code></td><td><code>lw rd, offset(rs1)</code></td><td>rd, rs1 ∈ x8-x15; offset 7 位 × 4</td></tr><tr><td><code>c.sw rs2&#39;, offset(rs1&#39;)</code></td><td><code>sw rs2, offset(rs1)</code></td><td>rs2, rs1 ∈ x8-x15; offset 7 位 × 4</td></tr><tr><td><code>c.ld rd&#39;, offset(rs1&#39;)</code></td><td><code>ld rd, offset(rs1)</code></td><td>rd, rs1 ∈ x8-x15; offset 8 位 × 8</td></tr><tr><td><code>c.sd rs2&#39;, offset(rs1&#39;)</code></td><td><code>sd rs2, offset(rs1)</code></td><td>rs2, rs1 ∈ x8-x15; offset 8 位 × 8</td></tr><tr><td><code>c.lwsp rd, offset(sp)</code></td><td><code>lw rd, offset(sp)</code></td><td>rd != x0; offset 8 位 × 4</td></tr><tr><td><code>c.swsp rs2, offset(sp)</code></td><td><code>sw rs2, offset(sp)</code></td><td>offset 8 位 × 4</td></tr><tr><td><code>c.ldsp rd, offset(sp)</code></td><td><code>ld rd, offset(sp)</code></td><td>rd != x0; offset 9 位 × 8</td></tr><tr><td><code>c.sdsp rs2, offset(sp)</code></td><td><code>sd rs2, offset(sp)</code></td><td>offset 9 位 × 8</td></tr></tbody></table><p>这里有两条重要的设计：</p><ol><li><strong>基于 sp 的 load/store</strong>（<code>c.lwsp</code>/<code>c.swsp</code>/<code>c.ldsp</code>/<code>c.sdsp</code>）可以访问任何寄存器（不限于 x8-x15）——因为 sp 自身已编码在 opcode 中，节省了 5 位</li><li><strong>基于任意寄存器的 load/store</strong>（<code>c.lw</code>/<code>c.sw</code>/<code>c.ld</code>/<code>c.sd</code>）源和目标都限制在 x8-x15——3 位寄存器编号编码</li></ol><h3 id="分支与跳转类" tabindex="-1">分支与跳转类 <a class="header-anchor" href="#分支与跳转类" aria-label="Permalink to “分支与跳转类”">​</a></h3><table tabindex="0"><thead><tr><th>压缩指令</th><th>等价 32 位</th><th>约束</th></tr></thead><tbody><tr><td><code>c.j offset</code></td><td><code>jal x0, offset</code></td><td>offset ∈ [±2KB]</td></tr><tr><td><code>c.jal offset</code></td><td><code>jal ra, offset</code></td><td>offset ∈ [±2KB]</td></tr><tr><td><code>c.jr rs1</code></td><td><code>jalr x0, rs1, 0</code></td><td>rs1 != x0</td></tr><tr><td><code>c.jalr rs1</code></td><td><code>jalr ra, rs1, 0</code></td><td>rs1 != x0</td></tr><tr><td><code>c.beqz rs1&#39;, offset</code></td><td><code>beq rs1, x0, offset</code></td><td>rs1 ∈ x8-x15; offset ∈ [±256]</td></tr><tr><td><code>c.bnez rs1&#39;, offset</code></td><td><code>bne rs1, x0, offset</code></td><td>rs1 ∈ x8-x15; offset ∈ [±256]</td></tr></tbody></table><p>注意 <code>c.jal</code> 是 RV32 专有——RV64 中 <code>c.jal</code> 不可用（其编码空间用于 <code>c.addiw</code>）。<code>c.j</code> 和 <code>c.jr</code> 是最常用的压缩跳转：子程序无条件转移的体积从 4 字节减小到 2 字节。</p><h2 id="编码策略" tabindex="-1">编码策略 <a class="header-anchor" href="#编码策略" aria-label="Permalink to “编码策略”">​</a></h2><h3 id="压缩标记-最低-2-位" tabindex="-1">压缩标记：最低 2 位 <a class="header-anchor" href="#压缩标记-最低-2-位" aria-label="Permalink to “压缩标记：最低 2 位”">​</a></h3><p>RISC-V 的指令长度解码规则非常简单——<strong>最低 2 位字节</strong>指示长度：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>bits[1:0] = 11 → 32 位指令（标准编码）</span></span>\n<span class="line"><span>bits[1:0] ≠ 11 → 16 位指令（压缩编码）</span></span>\n<span class="line"><span>             = 00, 01, 或 10 → 进一步区分压缩指令象限</span></span></code></pre></div><p>取指单元只需检查第一个 16 位半字的 bit[1:0]：</p><ul><li>如果 = 11：这是 32 位指令的开头，再取下一个半字组成完整指令</li><li>如果不是 11：这是 16 位压缩指令，停止取指</li></ul><p>这种设计将长度判定简化为 2 位——无需查表、无需状态机。在 16 位对齐允许的 ISA 中，这是最简洁的长度自识别方案之一。</p><h3 id="压缩指令的四个象限" tabindex="-1">压缩指令的四个象限 <a class="header-anchor" href="#压缩指令的四个象限" aria-label="Permalink to “压缩指令的四个象限”">​</a></h3><p>C 扩展将压缩指令空间按 opcode[1:0] 划分为四个象限：</p><table tabindex="0"><thead><tr><th>象限</th><th>bits[1:0]</th><th>指令类别</th></tr></thead><tbody><tr><td>C0</td><td>00</td><td>load/store、整数运算（基于 x8-x15）</td></tr><tr><td>C1</td><td>01</td><td>addi、addiw、li、lui、各种 ALU、跳转</td></tr><tr><td>C2</td><td>10</td><td>各种 ALU、跳转、基于 sp 的 load/store</td></tr></tbody></table><p>每个象限中的指令进一步由 bits[15:13]（funct3 等价物）和 bits[12:0] 的不同字段区分。完整的编码表不在本书范围——汇编器替你管理这一切。</p><h2 id="代码密度对比" tabindex="-1">代码密度对比 <a class="header-anchor" href="#代码密度对比" aria-label="Permalink to “代码密度对比”">​</a></h2><h3 id="同一函数-不加-c-扩展-vs-加-c-扩展" tabindex="-1">同一函数：不加 C 扩展 vs 加 C 扩展 <a class="header-anchor" href="#同一函数-不加-c-扩展-vs-加-c-扩展" aria-label="Permalink to “同一函数：不加 C 扩展 vs 加 C 扩展”">​</a></h3><p>以一个简单求和函数为例，展示 C 扩展带来的体积差异：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 不加 C 扩展 (objdump -d) ----</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 每条指令 4 字节</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000000000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;sum_array&gt;:</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00000337</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            lui    t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00000513</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            li     a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00000593</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            li     a1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   c:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   00b50663            beq    a0, a1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">18</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   00c50533            </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    a0, a0, a2        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  14</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   ff5ff06f            j       c               </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  18</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00008067</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">            ret</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # 4 bytes</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 总计: 7 条指令, 28 字节</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 加 C 扩展 (objdump -d -M no-aliases) ----</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000000000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;sum_array&gt;:</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0337</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                c.lui  t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4501</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                c.li   a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4581</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                c.li   a1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   c58d                c.beqz a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">18</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9532</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                c.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  a0, a2            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   a:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   bfd5                c.j    c                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   c:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   8082</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                c.jr   ra                 </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 2 bytes</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 总计: 7 条指令, 14 字节</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 体积节省: 50%</span></span></code></pre></div><p>实际大型程序的平均节省率约为 25%-30%——因为有些指令（如大范围 <code>lui</code>、有符号大偏移 load/store、跨寄存器文件的转换）不易压缩。</p><h3 id="汇编器如何处理" tabindex="-1">汇编器如何处理 <a class="header-anchor" href="#汇编器如何处理" aria-label="Permalink to “汇编器如何处理”">​</a></h3><p>写汇编代码时，你写出的是标准助记符。汇编器在处理每一条指令时执行以下决策：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 检查所有操作数是否在 x8-x15 内？立即数是否在压缩范围内？</span></span>\n<span class="line"><span>   → 是：生成 16 位编码</span></span>\n<span class="line"><span>   → 否：生成 32 位编码</span></span>\n<span class="line"><span>2. 检查是否可以用 .s 后缀显式强制（如 c.add.s 或 add.s）</span></span>\n<span class="line"><span>   → 程序员可显式控制：.s 后缀强制 16 位，否则不强制</span></span></code></pre></div><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 显式控制的例子</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  t0, t1           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 强制压缩形式（若不可用则汇编器报错）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s  t0, t1           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 同样效果：.s 后缀表示&quot;压缩&quot;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    t0, t1, t2       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 标准写法：汇编器自动选择</span></span></code></pre></div><p>对比 <code>objdump -d</code> 和 <code>objdump -d -M no-aliases</code> 可以看到压缩指令的展开：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-linux-gnu-objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 显示 c.addi, c.li 等压缩助记符</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">riscv64-linux-gnu-objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> no-aliases</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 显示 addi, c.addi 等标准助记符（但保留 c. 前缀）</span></span></code></pre></div><h2 id="c-扩展对汇编程序员的实际影响" tabindex="-1">C 扩展对汇编程序员的实际影响 <a class="header-anchor" href="#c-扩展对汇编程序员的实际影响" aria-label="Permalink to “C 扩展对汇编程序员的实际影响”">​</a></h2><h3 id="不需要你操心" tabindex="-1">不需要你操心 <a class="header-anchor" href="#不需要你操心" aria-label="Permalink to “不需要你操心”">​</a></h3><p>在日常开发中，C 扩展几乎完全透明。写 <code>addi sp, sp, -16</code>，汇编器自动生成 <code>c.addi sp, -16</code>——你不需要记忆哪些场景可用压缩形式。调试时在 objdump 输出中看到 <code>c.</code> 前缀是识别压缩指令的方式：<code>c.addi</code> 长 2 字节，<code>addi</code> 长 4 字节。</p><h3 id="但理解它有助于高效编程" tabindex="-1">但理解它有助于高效编程 <a class="header-anchor" href="#但理解它有助于高效编程" aria-label="Permalink to “但理解它有助于高效编程”">​</a></h3><p>当你在以下场景中手工汇编时，理解压缩约束能帮你写出更紧凑的代码：</p><ol><li><strong>优先使用 x8-x15 寄存器存储热数据</strong>：a0-a5 + s0-s1 共八个，对压缩指令全覆盖</li><li><strong>栈帧在 496 字节内时</strong>，<code>c.addi16sp</code> 替代两字节 <code>addi sp, sp, -N</code>（节省 2 字节）</li><li><strong>零与寄存器的比较用 <code>c.beqz</code>/<code>c.bnez</code></strong>：比完整 <code>beq rs, x0, label</code> 省 2 字节</li><li><strong>函数调用尾端使用 <code>c.jr ra</code> 而非 <code>ret</code></strong>：<code>ret</code> 展开为 <code>c.jr ra</code>（2 字节），比 <code>jalr x0, ra, 0</code> 省 2 字节</li></ol><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 紧凑的函数尾端</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.ldsp  ra, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 恢复 ra（2 字节）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.ldsp  s0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 恢复 s0（2 字节）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.addi16sp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 栈收缩（2 字节）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c.jr    ra               </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 返回（2 字节）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 尾端合计 8 字节 vs 无压缩的 16 字节</span></span></code></pre></div><h3 id="压缩指令集与指令集扩展的交互" tabindex="-1">压缩指令集与指令集扩展的交互 <a class="header-anchor" href="#压缩指令集与指令集扩展的交互" aria-label="Permalink to “压缩指令集与指令集扩展的交互”">​</a></h3><p>C 扩展独立于 M、A、F、D 等扩展。常见组合：</p><ul><li><strong>RV64IMAC</strong> = 基础整数 + 乘除 + 原子 + 压缩（嵌入式高性能 MCU 标配）</li><li><strong>RV64GC</strong> = IMAFD + C（通用计算指令集完整包）</li><li><strong>RV64IC</strong> = 基础整数 + 压缩（最小体积配置）</li></ul><p>汇编器中通过 <code>.option rvc</code> / <code>.option norvc</code> 开启/关闭压缩指令生成（GNU 汇编器默认 rvc 开启）。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>C 扩展将最常用的 50%-60% 指令压缩为 16 位编码，典型代码体积节省 25%-30%——每条压缩指令唯一映射到标准 32 位指令</li><li>压缩指令受限于 x8-x15 八个寄存器、较小立即数、无三操作数格式——汇编器自动在压缩和非压缩间选择</li><li>长度解码仅需检查 bit[1:0]：不等于 11 即为 16 位指令——RISC-V 最简洁的长度自识别方案</li><li>c.ldsp/c.sdsp（基于 sp 可满寄存器集）、c.beqz/c.bnez（零比较分支）、c.j/c.jr 是无条件跳转的紧凑形式</li><li>汇编器透明处理压缩；了解约束可帮你优先布局热数据到 x8-x15、控制栈帧在压缩范围内，从而挤出更多空间效率</li></ul>',50))])}]]);export{n as __pageData,r as default};
